tasks.command:
powershell -Command "$file = 'tests\steps\ContractF\create_contract_f.steps.ts'; $content = Get-Content $file -Raw; $old = @'
When('broker selects Abu Dhabi Islamic Bank as bank name on Contract F payment plan page', { timeout: 120000 }, async function (this: World) {
  const contractFPage = new ContractFPage(this.page);
  await contractFPage.selectBankNameAbuDhabiIslamicBank();
});
'@; $new = @'
When('broker selects Abu Dhabi Islamic Bank as bank name on Contract F payment plan page', { timeout: 120000 }, async function (this: World) {
  const bankDropdown = this.page.locator('xpath=/html/body/div/div/div/div/div/div[2]/div[2]/div/div/div[2]/div/div[2]/div/div[1]/div/div[3]/div/div/div[3]/div/div[2]/div/div/div/div/div[1]').first();
  await bankDropdown.waitFor({ state: 'visible', timeout: 30000 });
  await bankDropdown.click({ force: true });
  await this.page.waitForTimeout(500);
  const opts = this.page.locator('ng-option');
  const cnt = await opts.count();
  for (let i = 0; i < cnt; i++) {
    const o = opts.nth(i);
    const txt = await o.textContent();
    if (txt && txt.toLowerCase().includes('abu') && txt.toLowerCase().includes('dhabi')) {
      await o.click({ force: true });
      logger.info('Selected Abu Dhabi Islamic Bank');
      return;
    }
  }
  throw new Error('Bank not found');
});
'@; $content.Replace($old, $new) | Set-Content $file"
